INSERT INTO public.card_library (card_code, card_name, suit, value, core_theme, keywords, shadow_keywords, locked_in_summary, checked_out_summary)
VALUES
  ('AH', 'Ace of Hearts (The Search for Love Card)', 'hearts', 'A', 'The search for love', ARRAY['longing', 'devotion', 'openness', 'desire', 'magnetism']::text[], ARRAY['neediness', 'restlessness', 'fixation', 'loneliness']::text[], 'You move toward love with an open heart and trust what shows up.', 'You chase love from emptiness and lose yourself in the search.'),
  ('2H', 'Two of Hearts (The Love Affair Card)', 'hearts', '2', 'Partnership and union', ARRAY['connection', 'intimacy', 'partnership', 'devotion', 'presence']::text[], ARRAY['merging', 'possessiveness', 'jealousy', 'loss of self']::text[], 'You meet another person fully and let the bond shape you both.', 'You lose your edges in the relationship and disappear into them.'),
  ('3H', 'Three of Hearts (The Indecision in Love Card)', 'hearts', '3', 'Emotional indecision', ARRAY['choice', 'openness', 'exploration', 'options', 'curiosity']::text[], ARRAY['avoidance', 'scattering', 'indecision', 'evasion']::text[], 'You hold multiple feelings without forcing a choice before you are ready.', 'You stay vague to avoid commitment and leave others guessing.'),
  ('4H', 'Four of Hearts (The Family Card)', 'hearts', '4', 'Home and belonging', ARRAY['family', 'roots', 'sanctuary', 'loyalty', 'stability']::text[], ARRAY['enmeshment', 'control', 'rigidity', 'gatekeeping']::text[], 'You build a home people return to and feel safe in.', 'You confuse loyalty with control and call it love.'),
  ('5H', 'Five of Hearts (The Emotionally Restless Card)', 'hearts', '5', 'Emotional restlessness', ARRAY['change', 'exploration', 'movement', 'freedom', 'wonder']::text[], ARRAY['restlessness', 'escapism', 'drifting', 'abandonment']::text[], 'You let your feelings move you toward what is genuinely calling.', 'You leave before things get real and call it your truth.'),
  ('6H', 'Six of Hearts (The Peace Maker''s Card)', 'hearts', '6', 'Peace and balance', ARRAY['harmony', 'mediation', 'fairness', 'repair', 'listening']::text[], ARRAY['appeasing', 'conflict-avoidance', 'suppression', 'false peace']::text[], 'You hold space for hard conversations and bring people back to common ground.', 'You smooth things over to avoid your own discomfort.'),
  ('7H', 'Seven of Hearts (The Spiritual Love Card)', 'hearts', '7', 'Conscious love', ARRAY['surrender', 'trust', 'faith', 'depth', 'presence']::text[], ARRAY['martyrdom', 'idealising', 'denial', 'performance']::text[], 'You meet love as a practice and trust what it asks of you.', 'You spiritualise the wound instead of letting it heal.'),
  ('8H', 'Eight of Hearts (The Emotional Power Card)', 'hearts', '8', 'Emotional authority', ARRAY['presence', 'depth', 'intensity', 'magnetism', 'leadership']::text[], ARRAY['manipulation', 'intensity', 'control', 'withdrawal']::text[], 'You carry your feelings as power and let them move others.', 'You weaponise your feelings to win or to wound.'),
  ('9H', 'Nine of Hearts (The Universal Love Card)', 'hearts', '9', 'Letting go to love bigger', ARRAY['release', 'completion', 'generosity', 'compassion', 'expansion']::text[], ARRAY['martyr', 'exhaustion', 'grief', 'premature ending']::text[], 'You let endings make room for a larger kind of love.', 'You give until there is nothing left and call it love.'),
  ('10H', 'Ten of Hearts (The Social Success Card)', 'hearts', '10', 'Love through community', ARRAY['belonging', 'generosity', 'leadership', 'warmth', 'gathering']::text[], ARRAY['people-pleasing', 'performance', 'image', 'exhaustion']::text[], 'You bring people together and let love multiply through community.', 'You build a crowd to avoid the people who actually know you.'),
  ('JH', 'Jack of Hearts (The Sacrificial Love Card)', 'hearts', 'J', 'Devotion through giving', ARRAY['service', 'devotion', 'creativity', 'beauty', 'dedication']::text[], ARRAY['martyrdom', 'self-erasure', 'victim', 'performance']::text[], 'You give from fullness and let love be the work.', 'You give yourself away and call it love when it is fear.'),
  ('QH', 'Queen of Hearts (The Mother Card)', 'hearts', 'Q', 'Nurturing presence', ARRAY['care', 'depth', 'warmth', 'holding', 'intuition']::text[], ARRAY['smothering', 'control', 'sacrifice', 'martyrdom']::text[], 'You hold others without losing yourself.', 'You mother others into resentment and call yourself selfless.'),
  ('KH', 'King of Hearts (The Father Card)', 'hearts', 'K', 'Steady authority of love', ARRAY['presence', 'generosity', 'loyalty', 'strength', 'stability']::text[], ARRAY['rigidity', 'distance', 'performance', 'withholding']::text[], 'You lead with your heart and back it with your action.', 'You command love instead of meeting it.'),

  ('AD', 'Ace of Diamonds (The Desire for Money and Love Card)', 'diamonds', 'A', 'The hunger for value', ARRAY['ambition', 'drive', 'desire', 'magnetism', 'beginning']::text[], ARRAY['greed', 'restlessness', 'comparison', 'scarcity']::text[], 'You pursue what you want with clear desire and clean intent.', 'You chase money or attention to fill what cannot be filled by either.'),
  ('2D', 'Two of Diamonds (The Wheeler Dealer Card)', 'diamonds', '2', 'Partnership in value', ARRAY['negotiation', 'exchange', 'partnership', 'deal-making', 'fairness']::text[], ARRAY['scheming', 'manipulation', 'double-dealing', 'transactional']::text[], 'You make fair exchanges that build trust over time.', 'You optimise the deal and lose the relationship.'),
  ('3D', 'Three of Diamonds (The Undecided Values Card)', 'diamonds', '3', 'Conflict between wants', ARRAY['choice', 'exploration', 'multiplicity', 'options', 'learning']::text[], ARRAY['indecision', 'scattering', 'hedging', 'unfinished']::text[], 'You hold competing values and find the choice that honours all of them.', 'You start everything and finish nothing.'),
  ('4D', 'Four of Diamonds (The Card of Solid Values)', 'diamonds', '4', 'Financial foundation', ARRAY['stability', 'security', 'reliability', 'consistency', 'foundation']::text[], ARRAY['rigidity', 'hoarding', 'fear', 'narrow-mindedness']::text[], 'You build wealth slowly on what you actually believe in.', 'You hold tight to what you have and shrink your life to protect it.'),
  ('5D', 'Five of Diamonds (The Salesperson Card)', 'diamonds', '5', 'Persuasion and movement', ARRAY['charm', 'persuasion', 'momentum', 'opportunity', 'magnetism']::text[], ARRAY['hustle', 'exaggeration', 'hype', 'instability']::text[], 'You move money and people through clear, honest conviction.', 'You sell what you do not believe and call it the game.'),
  ('6D', 'Six of Diamonds (The Card of Financial Responsibility)', 'diamonds', '6', 'Karma in money', ARRAY['responsibility', 'fairness', 'accountability', 'balance', 'integrity']::text[], ARRAY['rigidity', 'harshness', 'self-punishment', 'austerity']::text[], 'You honour your debts and your word and let that be your wealth.', 'You keep score and call it justice.'),
  ('7D', 'Seven of Diamonds (The Card of Spiritual Values)', 'diamonds', '7', 'Faith over the ledger', ARRAY['trust', 'surrender', 'generosity', 'abundance', 'flow']::text[], ARRAY['scarcity', 'worry', 'hoarding', 'control']::text[], 'You trust what you cannot yet see in your bank account.', 'You count what is missing and build a life around the lack.'),
  ('8D', 'Eight of Diamonds (The Sun Card)', 'diamonds', '8', 'Power through visibility', ARRAY['brilliance', 'influence', 'success', 'magnetism', 'leadership']::text[], ARRAY['arrogance', 'domination', 'status-chasing', 'ego']::text[], 'You let your work shine and use your power to lift others.', 'You make yourself the center and call it leadership.'),
  ('9D', 'Nine of Diamonds (The Card of Universal Values)', 'diamonds', '9', 'Releasing what limits the wealth', ARRAY['completion', 'expansion', 'generosity', 'wisdom', 'release']::text[], ARRAY['loss', 'attachment', 'hoarding', 'scarcity']::text[], 'You let go of what kept your wealth small and build for everyone.', 'You hold on past the ending and call it loyalty.'),
  ('10D', 'Ten of Diamonds (The Blessed Card)', 'diamonds', '10', 'Earned abundance', ARRAY['abundance', 'fulfilment', 'success', 'gratitude', 'completion']::text[], ARRAY['complacency', 'entitlement', 'excess', 'ingratitude']::text[], 'You receive what you have built and steward it well.', 'You expect the abundance and stop tending the source.'),
  ('JD', 'Jack of Diamonds (The Financially Creative Card)', 'diamonds', 'J', 'Inventive value', ARRAY['innovation', 'creativity', 'opportunity', 'momentum', 'agility']::text[], ARRAY['scheming', 'shortcuts', 'restless', 'unreliable']::text[], 'You find new ways to make value where others see none.', 'You chase the next idea and finish none of them.'),
  ('QD', 'Queen of Diamonds (The Philanthropist Card)', 'diamonds', 'Q', 'Wealth in service', ARRAY['generosity', 'magnetism', 'leadership', 'vision', 'abundance']::text[], ARRAY['image-driven', 'transactional', 'status', 'control']::text[], 'You build wealth and direct it toward what matters.', 'You give to be seen giving.'),
  ('KD', 'King of Diamonds (The Businessman''s Card)', 'diamonds', 'K', 'Mastery in business', ARRAY['leadership', 'vision', 'command', 'strategy', 'authority']::text[], ARRAY['ruthlessness', 'control', 'status', 'isolation']::text[], 'You build something durable and lead it with clear judgement.', 'You confuse winning with worth.'),

  ('AC', 'Ace of Clubs (The Desire for Knowledge Card)', 'clubs', 'A', 'The hunger to understand', ARRAY['curiosity', 'study', 'openness', 'beginning', 'inquiry']::text[], ARRAY['scattered', 'restless', 'intellectualising', 'indecisive']::text[], 'You follow the question wherever it goes.', 'You collect information to avoid what you already know.'),
  ('2C', 'Two of Clubs (The Card of Conversation)', 'clubs', '2', 'Connection through dialogue', ARRAY['dialogue', 'exchange', 'partnership', 'listening', 'articulation']::text[], ARRAY['gossip', 'debate', 'scattering', 'double-talk']::text[], 'You think out loud with others and let the conversation refine you.', 'You talk to perform and listen to wait.'),
  ('3C', 'Three of Clubs (The Writer''s Card)', 'clubs', '3', 'Creative expression', ARRAY['writing', 'expression', 'creativity', 'articulation', 'voice']::text[], ARRAY['scattered', 'perfectionism', 'self-doubt', 'indecision']::text[], 'You put it in words even when the words are still forming.', 'You wait for clarity that only comes from writing it badly first.'),
  ('4C', 'Four of Clubs (The Card of Mental Satisfaction)', 'clubs', '4', 'Settled understanding', ARRAY['clarity', 'foundation', 'satisfaction', 'knowledge', 'structure']::text[], ARRAY['rigidity', 'dogma', 'certainty', 'narrow-mindedness']::text[], 'You build understanding that holds and let it ground your decisions.', 'You harden into being right and stop learning.'),
  ('5C', 'Five of Clubs (The Mentally and Emotionally Restless Card)', 'clubs', '5', 'Restless mind', ARRAY['change', 'exploration', 'curiosity', 'range', 'movement']::text[], ARRAY['scattered', 'restless', 'distracted', 'inconsistent']::text[], 'You let your mind range and find what wants to be studied.', 'You move from idea to idea to avoid going deep on any.'),
  ('6C', 'Six of Clubs (The Card of Higher Purpose)', 'clubs', '6', 'Words in service', ARRAY['meaning', 'purpose', 'communication', 'integrity', 'message']::text[], ARRAY['preaching', 'judgement', 'dogma', 'righteousness']::text[], 'You speak in service of something larger than you.', 'You preach to feel important.'),
  ('7C', 'Seven of Clubs (The Card of Spiritual Knowledge)', 'clubs', '7', 'Knowing through trust', ARRAY['wisdom', 'intuition', 'faith', 'depth', 'knowing']::text[], ARRAY['doubt', 'overthinking', 'worry', 'suspicion']::text[], 'You trust what you know without needing to prove it.', 'You drown what you know in second-guessing.'),
  ('8C', 'Eight of Clubs (The Card of Mental Power)', 'clubs', '8', 'Mind as authority', ARRAY['focus', 'conviction', 'influence', 'sharpness', 'command']::text[], ARRAY['dominance', 'manipulation', 'righteousness', 'intimidation']::text[], 'You think with conviction and let your mind move things.', 'You use your mind to win and call it being smart.'),
  ('9C', 'Nine of Clubs (The Card of Universal Knowledge)', 'clubs', '9', 'Wisdom released', ARRAY['wisdom', 'completion', 'broad view', 'generosity', 'integration']::text[], ARRAY['cynicism', 'weariness', 'bitterness', 'disillusion']::text[], 'You teach what you have learned and let the rest go.', 'You hold onto being right past its usefulness.'),
  ('10C', 'Ten of Clubs (The Teacher Card)', 'clubs', '10', 'Knowledge in transmission', ARRAY['teaching', 'mastery', 'articulation', 'generosity', 'leadership']::text[], ARRAY['lecturing', 'condescension', 'dogma', 'ego']::text[], 'You make complex things simple and give the knowledge away.', 'You teach to be admired.'),
  ('JC', 'Jack of Clubs (The Mentally Creative Card)', 'clubs', 'J', 'Inventive thought', ARRAY['ideation', 'creativity', 'agility', 'originality', 'expression']::text[], ARRAY['scheming', 'restless', 'scattered', 'manipulative']::text[], 'You see the angle no one else sees and bring it into form.', 'You play with ideas to feel clever.'),
  ('QC', 'Queen of Clubs (The Mother of Intuition Card)', 'clubs', 'Q', 'Intuitive intelligence', ARRAY['intuition', 'depth', 'knowing', 'presence', 'wisdom']::text[], ARRAY['overthinking', 'doubt', 'suspicion', 'second-guessing']::text[], 'You trust your read on a situation and act on it.', 'You doubt what you already know.'),
  ('KC', 'King of Clubs (King of Knowledge and Master of Distinctions)', 'clubs', 'K', 'Mental mastery', ARRAY['precision', 'authority', 'depth', 'clarity', 'mastery']::text[], ARRAY['arrogance', 'dogmatism', 'condescension', 'rigidity']::text[], 'You think with precision and lead with what you know.', 'You lecture instead of listening.'),

  ('AS', 'Ace of Spades (The Card of Ambition and The Magi Card)', 'spades', 'A', 'The drive to transform', ARRAY['ambition', 'beginning', 'will', 'vision', 'magic']::text[], ARRAY['obsession', 'restlessness', 'isolation', 'secrecy']::text[], 'You pursue what you were made for and let it transform you.', 'You chase the work to escape what you do not want to feel.'),
  ('2S', 'Two of Spades (The Friendship Card)', 'spades', '2', 'Partnership in work', ARRAY['collaboration', 'loyalty', 'shared purpose', 'trust', 'alignment']::text[], ARRAY['dependency', 'suspicion', 'conflict', 'rivalry']::text[], 'You work alongside others and let the partnership build something neither could alone.', 'You confuse loyalty with control.'),
  ('3S', 'Three of Spades (The Artist Card)', 'spades', '3', 'Creative work', ARRAY['creativity', 'expression', 'craft', 'devotion', 'artistry']::text[], ARRAY['self-doubt', 'perfectionism', 'scattering', 'comparison']::text[], 'You make the thing and let the making teach you what it wants to be.', 'You wait for the perfect conditions and never start.'),
  ('4S', 'Four of Spades (The Card of Security and Satisfaction)', 'spades', '4', 'Stability through work', ARRAY['foundation', 'reliability', 'mastery', 'satisfaction', 'structure']::text[], ARRAY['rigidity', 'complacency', 'fear', 'stagnation']::text[], 'You build something solid and trust the slow work.', 'You stay too long in what is comfortable and call it commitment.'),
  ('5S', 'Five of Spades (The Card of the Wanderer)', 'spades', '5', 'Restless work', ARRAY['change', 'exploration', 'movement', 'freedom', 'range']::text[], ARRAY['restless', 'scattered', 'escapist', 'untethered']::text[], 'You let the work move you across territories and pick up what each one teaches.', 'You leave before the work asks anything of you.'),
  ('6S', 'Six of Spades (The Card of Fate)', 'spades', '6', 'Karma and reckoning', ARRAY['alignment', 'integrity', 'accountability', 'fate', 'completion']::text[], ARRAY['passivity', 'fatalism', 'victim', 'resignation']::text[], 'You meet what is yours to do and do it without complaint.', 'You blame fate to avoid the work in front of you.'),
  ('7S', 'Seven of Spades (The Card of Faith)', 'spades', '7', 'Trust in the process', ARRAY['faith', 'surrender', 'perseverance', 'trust', 'depth']::text[], ARRAY['doubt', 'control', 'discouragement', 'impatience']::text[], 'You keep going through the part where there is no proof yet.', 'You give up just before the work was about to land.'),
  ('8S', 'Eight of Spades (Power Through Work)', 'spades', '8', 'Authority through doing', ARRAY['command', 'mastery', 'focus', 'capability', 'will']::text[], ARRAY['domination', 'control', 'workaholism', 'intimidation']::text[], 'You meet the work with everything you have and let your power show through what you build.', 'You overpower what cannot be overpowered.'),
  ('9S', 'Nine of Spades (The Universal Giver Card)', 'spades', '9', 'Service through release', ARRAY['completion', 'service', 'release', 'devotion', 'integration']::text[], ARRAY['martyr', 'exhaustion', 'burnout', 'victim']::text[], 'You finish the chapter and give the work back to the world.', 'You give until there is nothing left and call it noble.'),
  ('10S', 'Ten of Spades (The Workaholic Card)', 'spades', '10', 'Work as identity', ARRAY['dedication', 'capacity', 'mastery', 'productivity', 'drive']::text[], ARRAY['workaholism', 'no off switch', 'burnout', 'avoidance']::text[], 'You work hard because the work matters and you go home when it is done.', 'You work to avoid the rest of your life.'),
  ('JS', 'Jack of Spades (The Spiritual Initiate)', 'spades', 'J', 'Threshold of mastery', ARRAY['initiation', 'devotion', 'learning', 'transformation', 'courage']::text[], ARRAY['trickster', 'scheming', 'immaturity', 'evasion']::text[], 'You step into the apprenticeship and let it remake you.', 'You trick your way around the lesson you were here to learn.'),
  ('QS', 'Queen of Spades (The Card of Self-Mastery)', 'spades', 'Q', 'Inner authority', ARRAY['discipline', 'mastery', 'depth', 'sovereignty', 'integrity']::text[], ARRAY['harshness', 'isolation', 'control', 'severity']::text[], 'You govern yourself before you try to govern anything else.', 'You rule yourself with cruelty and call it discipline.'),
  ('KS', 'King of Spades (The Master Card)', 'spades', 'K', 'Authority of the soul', ARRAY['mastery', 'command', 'integrity', 'vision', 'wisdom']::text[], ARRAY['tyranny', 'isolation', 'control', 'severity']::text[], 'You hold the highest standard for yourself first and let that authority lead others.', 'You demand from others what you will not give yourself.'),

  ('JKR', 'The Joker (The Wild Card)', 'joker', 'Joker', 'The wild card', ARRAY['freedom', 'surprise', 'humour', 'range', 'possibility']::text[], ARRAY['chaos', 'instability', 'evasion', 'irreverence']::text[], 'You move outside the rules and let your range be the gift.', 'You refuse the structure and call it freedom.')
ON CONFLICT (card_code) DO NOTHING;
